+/// Outcome of executing a single SQL statement.
+#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
+pub enum StmtOutcome {
+    /// Query returned rows.
+    Rows(Vec<Vec<NormalizedValue>>),
+    /// DML executed with N affected rows.
+    Execute(usize),
+    /// Statement failed.
