+
+    #[test]
+    fn no_observer_no_panic() {
+        let shared: SharedObserver = None;
+        emit_fcw_base_drift(
+            &shared,
+            make_page(1),
+            make_txn(1),
+            CommitSeq::new(1),
+            false,
+            false,
