+        emit_ssi_abort(
+            &shared,
+            make_token(1),
+            SsiAbortCategory::MarkedForAbort,
+            0,
+            0,
+        );
+        emit_page_lock_contention(&shared, make_page(1), make_txn(1), make_txn(2));
+        emit_conflict_resolved(&shared, make_txn(1), 0, CommitSeq::new(1));
+    }
+}

